mapper.update:
UPDATE business_idempotent
SET idempotent_status     = #{idempotentStatus},
    object_version_number = #{objectVersionNumber} + 1,
    last_modified_date    = #{lastModifiedDate}
WHERE unique_key = #{uniqueKey}
  AND object_version_number = #{objectVersionNumber}

UPDATE business_idempotent
SET idempotent_status     = #{idempotentStatus},
    response              = #{response},
    object_version_number = #{objectVersionNumber} + 1,
    last_modified_date    = #{lastModifiedDate}
WHERE unique_key = #{uniqueKey}
  AND object_version_number = #{objectVersionNumber}
